import React, { useState } from 'react';
import '../styles/practice.css';

const practiceAreas = [
    "Intellectual Property",
    "Suspension of Payment/Bankruptcy Law & Debt Recovery",
    "Corporate and Investment",
    "Mergers & Acquisitions",
    "Antitrust & Competition Law",
    "Dispute Resolution",
    "Family Law",
    "Private Data Protection"
];

const practiceDetails = {
    "Intellectual Property": `INTELLECTUAL PROPERTY (IP) PROSECUTION & PORTFOLIO MANAGEMENT
We are experienced in all aspects of establishing, managing, and protecting all IP aspects including, trademarks, patents, industrial designs, and copyrights. We combine practical, efficient advice with cost-effective legal services for a broad range of IP issues because we understand that your IP are valuable assets that help define your unique corporate identity. We have handled IP Portfolios on behalf of a broad range of clients, including software industries, food and beverages, education services, fashions, IT companies, telecommunications, financial services, pharmacies, and consumer products. We have been closely working and collaborating with IP Agents in Singapore, Malaysia, Indonesia, Thailand, the Philippines, Vietnam, and Myanmar so that we will be able to serve our clients in all ten ASEAN countries, as well as other jurisdictions such as Japan, Hong Kong, and Australia.

INTELLECTUAL PROPERTY (IP) LITIGATION & ENFORCEMENT
We work closely with clients in the development of effective enforcement strategies for their IP portfolios and in the defense of enforcement actions. We have a strong anti-counterfeiting team where since our earliest establishment we have been retained by several world’s largest software manufacturers to carry out software license anti-counterfeiting projects in Indonesia. In addition, we have experience in representing clients as plaintiff and defendant in trademark cancellation cases before the Commercial Court and the Supreme Court.`
};

const PracticeAreas = () => {
    const [selectedArea, setSelectedArea] = useState("Intellectual Property");

    return (
        <div className="practice-container">
            <div className="practice-list">
                <ul>
                    {practiceAreas.map((area, index) => (
                        <li 
                            key={index} 
                            className={selectedArea === area ? "active" : ""}
                            onClick={() => setSelectedArea(area)}
                        >
                            {area}
                        </li>
                    ))}
                </ul>
            </div>
            <div className="practice-text">
                <h2>{selectedArea.toUpperCase()}</h2>
                <p>{practiceDetails[selectedArea] || "More details coming soon..."}</p>
            </div>
        </div>
    );
};

export default PracticeAreas;
